<script setup>import{onMounted,ref}from'vue';import axios from'axios';import PageHeader from'../components/PageHeader.vue';import{useAuthStore}from'../stores/auth';const auth=useAuthStore(),orders=ref([]),message=ref('');async function load(){orders.value=(await axios.get('/api/orders')).data.data}onMounted(load);async function status(o,s){try{await axios.put(`/api/orders/${o.id}/status`,{status:s});await load()}catch(e){message.value=e.response?.data?.message||'Update failed.'}}async function receive(o){if(!confirm('Confirm all materials were received and release payment?'))return;await axios.post(`/api/orders/${o.id}/receive`);await load()}async function cancel(o){if(!confirm('Cancel this order and release reserved inventory?'))return;await axios.post(`/api/orders/${o.id}/cancel`);await load()}</script>
<template><PageHeader :title="auth.role==='user'?'My orders':'Order fulfillment'" subtitle="Protected payments and inventory reservations"/><p v-if="message" class="notice">{{message}}</p><section class="panel table-wrap"><table><thead><tr><th>Reference</th><th>Customer</th><th>Items</th><th>Total</th><th>Delivery</th><th>Payment</th><th>Action</th></tr></thead><tbody><tr v-for="o in orders" :key="o.id"><td><strong>{{o.reference}}</strong><small>{{new Date(o.created_at).toLocaleString()}}</small></td><td>{{o.customer?.name}}</td><td>{{o.items.map(i=>`${i.product_name} × ${i.quantity}`).join(', ')}}</td><td>₱{{Number(o.total).toLocaleString()}}</td><td><span class="tag">{{o.status}}</span></td><td><span class="tag" :class="{warn:o.payment_status!=='paid'}">{{o.payment_status}}</span></td><td><div class="actions"><button v-if="['admin','assistant'].includes(auth.role)&&o.status==='preparing'" class="btn tiny" @click="status(o,'dispatched')">Dispatch</button><button v-if="['admin','assistant'].includes(auth.role)&&o.status==='dispatched'" class="btn tiny primary" @click="status(o,'delivered')">Delivered</button><button v-if="auth.role==='user'&&o.status==='delivered'" class="btn tiny primary" @click="receive(o)">Confirm receipt</button><button v-if="['preparing','dispatched'].includes(o.status)&&(auth.role==='admin'||auth.role==='user')" class="btn tiny danger" @click="cancel(o)">Cancel</button></div></td></tr><tr v-if="!orders.length"><td colspan="7"><div class="empty">No orders yet.</div></td></tr></tbody></table></section></template>
